import { LanguageHandler } from "../../src/lib/language";
import { globalBaseConfig } from "../../src/config/global-base-config";
import { getEnvironmentLabel, getBetaFromHostname, isChinaDomain } from "../../src/lib/environment";
import mockLanguageFile from "../mocks/language/en.json";
import mockComponentLanguageJson from "../mocks/language/componentFallback.json";

jest.mock("../../src/lib/environment", () => {
  const baseConfig = require("../../src/config/global-base-config");
  return {
    getBrandFromHostname: jest.fn().mockReturnValue(baseConfig.globalBaseConfig.BRANDS[0]),
    getEnvironmentLabel: jest.fn().mockReturnValue("test"),
    getBetaFromHostname: jest.fn().mockReturnValue(false),
    isChinaDomain: jest.fn().mockReturnValue(false)
  };
});

describe("language", () => {
  const langFilePathLocal = "../../tests/mocks/language";
  const keyRootId = "MY-SITECORE-KEY";
  const langFilePathWeb = `https://assetst.maerskline.com/content/keys/query/${keyRootId}`;
  const keyRootVersion = 99;
  const expectedSC9Path = "https://assetst.maerskline.com/content/keys/query/" + keyRootId;
  const langFilePathAPMT = "https://api.apmterminals.com/headless-keys/apps/my-profile";
  describe("constructor", () => {
    describe("LanguageHandler", () => {
      it("should throw error when langFilePathWeb is missing, langFilePathLocal is set", () => {
        expect(() => {
          new LanguageHandler(null, langFilePathLocal);
        }).toThrow(new Error("langFilePathWeb or keyRootId are required!"));
      });

      it("should throw error when langFilePathWeb is set, langFilePathLocal and langJson is missing", () => {
        expect(() => {
          new LanguageHandler(langFilePathWeb, null);
        }).toThrow(new Error("langFilePathLocal or langJson required!"));
      });

      it("langFilePathLocal is missing, and langJson is set", () => {
        const languageHandler = new LanguageHandler(
          langFilePathWeb,
          null,
          null,
          null,
          null,
          null,
          mockComponentLanguageJson
        );
        expect(languageHandler.langJson).toEqual(mockComponentLanguageJson);
      });
    });

    test.each`
      langFilePathWebLocal | langFilePathLocalLocal | keyRootIdLocal | tagsLocal    | keyRootVersionLocal | brandCodeLocal | langJsonLocal                | isAPMT   | apmtAppName     | consumerKey
      ${langFilePathWeb}   | ${undefined}           | ${undefined}   | ${undefined} | ${undefined}        | ${undefined}   | ${mockComponentLanguageJson} | ${false} | ${undefined}    | ${undefined}
      ${langFilePathWeb}   | ${langFilePathLocal}   | ${undefined}   | ${undefined} | ${undefined}        | ${undefined}   | ${undefined}                 | ${false} | ${undefined}    | ${undefined}
      ${langFilePathWeb}   | ${langFilePathLocal}   | ${keyRootId}   | ${undefined} | ${undefined}        | ${undefined}   | ${undefined}                 | ${false} | ${undefined}    | ${undefined}
      ${langFilePathWeb}   | ${langFilePathLocal}   | ${keyRootId}   | ${["foo"]}   | ${undefined}        | ${undefined}   | ${undefined}                 | ${false} | ${undefined}    | ${undefined}
      ${langFilePathWeb}   | ${langFilePathLocal}   | ${keyRootId}   | ${["foo"]}   | ${keyRootVersion}   | ${undefined}   | ${undefined}                 | ${false} | ${undefined}    | ${undefined}
      ${langFilePathWeb}   | ${langFilePathLocal}   | ${keyRootId}   | ${["foo"]}   | ${keyRootVersion}   | ${"sudu"}      | ${undefined}                 | ${false} | ${undefined}    | ${undefined}
      ${langFilePathWeb}   | ${langFilePathLocal}   | ${keyRootId}   | ${["foo"]}   | ${keyRootVersion}   | ${"sudu"}      | ${mockComponentLanguageJson} | ${false} | ${undefined}    | ${undefined}
      ${langFilePathAPMT}  | ${langFilePathLocal}   | ${keyRootId}   | ${undefined} | ${keyRootVersion}   | ${undefined}   | ${mockComponentLanguageJson} | ${true}  | ${"my-profile"} | ${"my-profile-consumer-key"}
    `(
      "should set data based on params passed in the constructor",
      ({
        langFilePathWebLocal,
        langFilePathLocalLocal,
        keyRootIdLocal,
        tagsLocal,
        keyRootVersionLocal,
        brandCodeLocal,
        langJsonLocal,
        isAPMT,
        apmtAppName,
        consumerKey
      }) => {
        const languageHandler = new LanguageHandler(
          langFilePathWebLocal,
          langFilePathLocalLocal,
          keyRootIdLocal,
          tagsLocal,
          keyRootVersionLocal,
          brandCodeLocal,
          langJsonLocal,
          isAPMT,
          apmtAppName,
          consumerKey
        );
        expect(languageHandler).not.toBeNull();
        expect(languageHandler.langFilePathWeb).toEqual(langFilePathWebLocal);
        expect(languageHandler.langFilePathLocal).toEqual(langFilePathLocalLocal);
        expect(languageHandler.keyRootId).toEqual(keyRootIdLocal);
        // expect(languageHandler.tags).toEqual(tagsLocal || []);
        expect(languageHandler.keyRootVersion).toEqual(keyRootVersionLocal || "1");
        // expect(languageHandler.brandCode).toEqual(brandCodeLocal || "maeu");
        expect(languageHandler.langJson).toEqual(langJsonLocal);
      }
    );
  });

  describe("getLanguageData", () => {
    it("language is missing", async () => {
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      try {
        await languageHandler.getLanguageData();
      } catch (error) {
        expect(error).toEqual(new Error("language is required!"));
      }
    });

    it("calls loadLanguageFromURL with provided language -> resolve", async () => {
      const language = "dk";
      const data = {
        test: "test"
      };
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      languageHandler.loadLanguageFromURL = jest.fn().mockImplementationOnce(() => Promise.resolve(data));
      await expect(languageHandler.getLanguageData(language)).resolves.toEqual(data);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledTimes(1);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(`${langFilePathWeb}/${language}.json`);
    });

    it("calls loadLanguageFromURL with provided language for sitecore with a tag", async () => {
      const language = "zh_hans";
      const data = {
        test: "test"
      };
      const languageHandler = new LanguageHandler(
        langFilePathWeb,
        langFilePathLocal,
        keyRootId,
        undefined,
        keyRootVersion
      );
      languageHandler.loadLanguageFromURL = jest.fn().mockImplementationOnce(() => Promise.resolve(data));
      await expect(languageHandler.getLanguageData(language)).resolves.toEqual(data);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledTimes(1);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(
        `${expectedSC9Path}/${language}.json?carrierCode=maeu&version=v${keyRootVersion}`
      );
    });

    it("calls loadLanguageFromURL with provided language -> reject, calls loadLanguageFromURL with DEFAULT language -> resolves", async () => {
      const language = "dk";
      const data = {
        test: "test"
      };
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      languageHandler.loadLanguageFromURL = jest
        .fn()
        .mockImplementationOnce(() => Promise.reject())
        .mockImplementationOnce(() => Promise.resolve(data));
      await expect(languageHandler.getLanguageData(language)).resolves.toEqual(data);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledTimes(2);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(`${langFilePathWeb}/${language}.json`);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(
        `${langFilePathWeb}/${globalBaseConfig.DEFAULT_LANGUAGE}.json`
      );
    });

    it("calls loadLanguageFromURL with provided language -> reject, calls loadLanguageFromURL with DEFAULT language -> rejects", async () => {
      const language = "dk";
      const data = {
        test: "test"
      };
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      languageHandler.loadLanguageFromURL = jest
        .fn()
        .mockImplementationOnce(() => Promise.reject())
        .mockImplementationOnce(() => Promise.reject())
        .mockImplementationOnce(() => Promise.resolve(data));
      await expect(languageHandler.getLanguageData(language)).resolves.toEqual(data);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledTimes(3);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(`${langFilePathWeb}/${language}.json`);
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(
        `${langFilePathWeb}/${globalBaseConfig.DEFAULT_LANGUAGE}.json`
      );
      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(
        `${langFilePathLocal}/${globalBaseConfig.DEFAULT_LANGUAGE}.json`
      );
    });

    it("calls loadLanguageFromURL with provided language -> reject, calls loadLanguageFromURL with DEFAULT language -> rejects", async () => {
      const language = "dk";
      const languageHandler = new LanguageHandler(
        langFilePathWeb,
        null,
        null,
        [],
        "1",
        null,
        mockComponentLanguageJson
      );
      languageHandler.loadLanguageFromURL = jest
        .fn()
        .mockImplementationOnce(() => Promise.reject())
        .mockImplementationOnce(() => Promise.reject())
        .mockImplementationOnce(() => Promise.resolve(mockComponentLanguageJson));

      expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledTimes(0);
      await expect(languageHandler.getLanguageData(language)).resolves.toEqual(mockComponentLanguageJson);
    });

    it("calls loadLanguageFromURL with provided language -> reject, calls loadLanguageFromURL with DEFAULT language -> rejects, loadLanguageFromURL with local file -> rejects", async () => {
      const language = "dk";
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      const errorForReject = { testKey: "test Value" };
      languageHandler.loadLanguageFromURL = jest
        .fn()
        .mockImplementationOnce(() => Promise.reject())
        .mockImplementationOnce(() => Promise.reject())
        .mockImplementationOnce(() => Promise.reject(errorForReject));
      try {
        await languageHandler.getLanguageData(language);
      } catch (error) {
        expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledTimes(3);
        expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(`${langFilePathWeb}/${language}.json`);
        expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(
          `${langFilePathWeb}/${globalBaseConfig.DEFAULT_LANGUAGE}.json`
        );
        expect(languageHandler.loadLanguageFromURL).toHaveBeenCalledWith(
          `${langFilePathLocal}/${globalBaseConfig.DEFAULT_LANGUAGE}.json`
        );
        expect(error).toEqual(new Error(JSON.stringify(errorForReject)));
      }
    });
  });

  describe("assembleAssetUrl", () => {
    test.each`
      envLabel       | beta     | cnDomain | language     | tags         | keyRootId    | expectedPath                                                                                                                    | isAPMT   | apmtAppName     | consumerKey
      ${"localhost"} | ${false} | ${false} | ${"zh_hans"} | ${undefined} | ${keyRootId} | ${`https://assetst.maerskline.com/content/keys/query/${keyRootId}/zh_hans.json?carrierCode=maeu&version=v1`}                    | ${false} | ${undefined}    | ${undefined}
      ${"test"}      | ${false} | ${false} | ${"de-DE"}   | ${undefined} | ${keyRootId} | ${`https://assetst.maerskline.com/content/keys/query/${keyRootId}/de-DE.json?carrierCode=maeu&version=v1`}                      | ${false} | ${undefined}    | ${undefined}
      ${"test"}      | ${false} | ${false} | ${"de-DE"}   | ${["foo"]}   | ${keyRootId} | ${`https://assetst.maerskline.com/content/keys/query/${keyRootId}/de-DE.json?carrierCode=maeu&version=v1&tags=foo`}             | ${false} | ${undefined}    | ${undefined}
      ${"preprod"}   | ${false} | ${false} | ${"en"}      | ${undefined} | ${keyRootId} | ${`https://assetsd.maerskline.com/content/keys/query/${keyRootId}/en.json?carrierCode=maeu&version=v1`}                         | ${false} | ${undefined}    | ${undefined}
      ${"preprod"}   | ${false} | ${false} | ${"en"}      | ${[]}        | ${keyRootId} | ${`https://assetsd.maerskline.com/content/keys/query/${keyRootId}/en.json?carrierCode=maeu&version=v1`}                         | ${false} | ${undefined}    | ${undefined}
      ${"prod"}      | ${false} | ${false} | ${"pt-BR"}   | ${undefined} | ${keyRootId} | ${`https://assets.maerskline.com/content/keys/query/${keyRootId}/pt-BR.json?carrierCode=maeu&version=v1`}                       | ${false} | ${undefined}    | ${undefined}
      ${"prod"}      | ${true}  | ${false} | ${"pt-BR"}   | ${undefined} | ${keyRootId} | ${`https://assets.maerskline.com/content/keys/query/${keyRootId}/pt-BR.json?carrierCode=maeu&version=v1&tags=beta`}             | ${false} | ${undefined}    | ${undefined}
      ${"prod"}      | ${false} | ${true}  | ${"zh_hans"} | ${null}      | ${keyRootId} | ${`https://assets.maerskline.com/content/keys/query/${keyRootId}/zh_hans.json?carrierCode=maeu&version=v1&tags=china`}          | ${false} | ${undefined}    | ${undefined}
      ${"prod"}      | ${true}  | ${true}  | ${"zh_hans"} | ${[]}        | ${keyRootId} | ${`https://assets.maerskline.com/content/keys/query/${keyRootId}/zh_hans.json?carrierCode=maeu&version=v1&tags=china,beta`}     | ${false} | ${undefined}    | ${undefined}
      ${"prod"}      | ${true}  | ${true}  | ${"zh_hans"} | ${["foo"]}   | ${keyRootId} | ${`https://assets.maerskline.com/content/keys/query/${keyRootId}/zh_hans.json?carrierCode=maeu&version=v1&tags=china,beta,foo`} | ${false} | ${undefined}    | ${undefined}
      ${"prod"}      | ${true}  | ${true}  | ${"zh_hans"} | ${["foo"]}   | ${undefined} | ${`https://assetst.maerskline.com/content/keys/query/${keyRootId}/zh_hans.json`}                                                | ${false} | ${undefined}    | ${undefined}
      ${"prod"}      | ${false} | ${false} | ${"en"}      | ${undefined} | ${keyRootId} | ${`https://api.apmterminals.com/headless-keys/apps/my-account-consumer-key/en&tags=china,beta?sc_apikey=MY-SITECORE-KEY`}       | ${true}  | ${"my-account"} | ${"my-account-consumer-key"}
    `(
      "should constructs the URL correctly for sitecore for $envLabel",
      async ({
        envLabel,
        beta,
        cnDomain,
        language,
        tags,
        keyRootId,
        expectedPath,
        isAPMT,
        apmtAppName,
        consumerKey
      }) => {
        const data = {
          test: "test"
        };
        getEnvironmentLabel.mockReturnValueOnce(envLabel);
        getBetaFromHostname.mockReturnValueOnce(beta);
        isChinaDomain.mockReturnValueOnce(cnDomain);
        const languageHandler = new LanguageHandler(
          langFilePathWeb,
          langFilePathLocal,
          keyRootId,
          tags,
          null,
          null,
          isAPMT,
          apmtAppName,
          consumerKey
        );
        languageHandler.loadLanguageFromURL = jest.fn().mockImplementationOnce(() => Promise.resolve(data));
        expect(languageHandler.assembleAssetUrl(language)).toEqual(expectedPath);
      }
    );
  });

  describe("loadLanguageFromURL", () => {
    it("should throw error when language is missing", async () => {
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      try {
        await languageHandler.loadLanguageFromURL();
      } catch (error) {
        expect(error).toEqual(new Error("path is required!"));
      }
    });

    it("should throw error when fetch resolves with not 'OK' status", async () => {
      const language = "dk";
      const data = {
        test: "test"
      };
      const response = {
        ok: false,
        json: () => Promise.resolve(data)
      };
      global.fetch = jest.fn().mockImplementationOnce(() => Promise.resolve(response));
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      try {
        await languageHandler.loadLanguageFromURL(`${langFilePathWeb}/${language}.json`);
      } catch (error) {
        expect(global.fetch).toHaveBeenCalledTimes(1);
        expect(global.fetch).toHaveBeenCalledWith(`${langFilePathWeb}/${language}.json`);
        expect(error).toEqual(new Error(JSON.stringify(response)));
      }
    });

    it("should throw error when fetch resolves with not 'OK' status testing for APMT", async () => {
      const language = "en";
      const data = {
        test: "test"
      };
      const response = {
        ok: true,
        json: () => Promise.resolve(data)
      };
      global.fetch = jest.fn().mockImplementationOnce(() => {
        Promise.resolve(response);
      });
      const languageHandler = new LanguageHandler(
        langFilePathAPMT,
        langFilePathLocal,
        null,
        null,
        null,
        null,
        null,
        true,
        "my-profile",
        "MY-CONSUMER-KEY"
      );
      try {
        await languageHandler.loadLanguageFromURL(`${langFilePathAPMT}/${language}?sc_apikey=MY-SITECORE-KEY`);
      } catch (error) {
        expect(global.fetch).toHaveBeenCalledTimes(1);
        expect(global.fetch).toHaveBeenCalledWith(`${langFilePathAPMT}/${language}?sc_apikey=MY-SITECORE-KEY`, {
          headers: {
            "Consumer-Key": "MY-CONSUMER-KEY"
          }
        });
      }
    });

    it("should work when fetch resolves", async () => {
      const language = "dk";
      const data = {
        test: "test"
      };
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(data)
        })
      );
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      languageHandler.loadDefaultLanguageFromFile = jest.fn().mockImplementationOnce(() => data);
      await expect(languageHandler.loadLanguageFromURL(`${langFilePathWeb}/${language}.json`)).resolves.toEqual(data);
      expect(global.fetch).toHaveBeenCalledTimes(1);
      expect(global.fetch).toHaveBeenCalledWith(`${langFilePathWeb}/${language}.json`);
    });

    it("should throw fetch response when fetch rejects", async () => {
      const language = "dk";
      const data = {
        test: "test"
      };
      const errorForReject = "test";
      global.fetch = jest.fn().mockImplementationOnce(() => Promise.reject(errorForReject));
      const languageHandler = new LanguageHandler(langFilePathWeb, langFilePathLocal);
      languageHandler.loadDefaultLanguageFromFile = jest.fn().mockImplementationOnce(() => data);
      try {
        await languageHandler.loadLanguageFromURL(`${langFilePathWeb}/${language}.json`);
      } catch (error) {
        expect(global.fetch).toHaveBeenCalledTimes(1);
        expect(global.fetch).toHaveBeenCalledWith(`${langFilePathWeb}/${language}.json`);
        expect(error).toEqual(errorForReject);
      }
    });
  });
});
